mapper.select:
select mao.id , mao.brush_person_id brushPersonId , mao.tb_order_id tbOrderId , mao.order_time orderTime , mao.order_state orderState , mao.seed_money seedMoney , mao.hire_money hireMoney , mao.way_bill_money wayBillMoney , mao.way_bill_code wayBillCode , mao.way_bill_name wayBillName , mao.platform_type platformType , mao.hire_is_pay hireIsPay , mao.is_evaluated isEvaluated , mao.seed_is_pay seedIsPay , mao.settlement_time settlementTime , mo.nick_name brushPersonName , mp.title productName , mp.code productId
from brush_order mao left join brush_person mo on mao.brush_person_id = mo.id left join platform_product mp on mao.product_id = mp.code
where 1=1
and mao.platform_type = #{mallAddOrderPageDto.platformType}
and mao.brush_person_id = #{mallAddOrderPageDto.brushId}
and mao.tb_order_id = #{mallAddOrderPageDto.tbOrderId}
and mao.order_state = #{mallAddOrderPageDto.orderstate}
and mao.hire_is_pay = #{mallAddOrderPageDto.hireIsPay}
and mao.seed_is_pay = #{mallAddOrderPageDto.seedIsPay}
and mao.create_time >= #{mallAddOrderPageDto.createTimeStart}
and mao.create_time <= #{mallAddOrderPageDto.createTimeEnd}
order by mao.order_time desc, mao.order_state asc

select mo.id brushPersonId , mo.nick_name brushPersonName , count(mao.id) totalOrderCount , sum(case when mao.order_state = 3 then 1 else 0 end) completedOrderCount , coalesce(sum(mao.hire_money), 0) totalCommission , coalesce(sum(case when mao.hire_is_pay = 1 then mao.hire_money else 0 end), 0) paidCommission , coalesce(sum(case when mao.hire_is_pay = 0 then mao.hire_money else 0 end), 0) unpaidCommission , coalesce(sum(mao.seed_money), 0) totalSeedMoney , coalesce(sum(case when mao.seed_is_pay = 0 then mao.seed_money else 0 end), 0) unpaidSeedMoney from brush_person mo left join brush_order mao on mo.id = mao.brush_person_id where mo.type = 1
and mao.platform_type = #{platformType}
group by mo.id, mo.nick_name order by totalOrderCount desc
